	const queue: (
		| { type: 'result'; result: R; item: T }
		| { type: 'error'; error: unknown; item: T }
	)[] = [];
	let resolveWaiting: (() => void) | null = null;
	let currentIndex = 0;
	let activeWorkers = 0;
	let done = false;

	async function processNext(): Promise<void> {
		while (currentIndex < items.length) {
			const index = currentIndex++;
			const item = items[index];

			if (item === undefined) {
				continue;
			}

			try {
				const result = await handler(item);
				queue.push({ type: 'result', result, item });
			} catch (error) {
				queue.push({ type: 'error', error, item });
			}

			if (resolveWaiting) {
				resolveWaiting();
				resolveWaiting = null;
			}
		}

		activeWorkers--;
		if (activeWorkers === 0) {
			done = true;
			if (resolveWaiting) {
				resolveWaiting();
				resolveWaiting = null;
			}
		}
	}

	activeWorkers = Math.min(concurrency, items.length);
	for (let i = 0; i < activeWorkers; i++) {
		void processNext();
	}

	while (!done || queue.length > 0) {
		if (queue.length === 0 && !done) {
			await new Promise<void>((resolve) => {
				resolveWaiting = resolve;
			});
		}

		while (queue.length > 0) {
			const entry = queue.shift();
			if (entry) {
				if (entry.type === 'result') {
					yield { result: entry.result, item: entry.item };
				} else {
					yield { error: entry.error, item: entry.item };
				}
			}
		}
	}
}

